def generate_transaction_id():
    import uuid
    return f"TXN-{uuid.uuid4().hex[:12].upper()}"


class FinancialService(Service):
    """Financial Services SOAP API with multiple operations."""

    @rpc(
        Unicode(min_occurs=1),
        _returns=BalanceResponse,
        _soap_action="http://financialservices.example.com/getBalance",
        _operation_name="getBalance",
    )
    def getBalance(ctx, account_id):
        """Retrieve the current balance for a given account."""
        logger.info(f"getBalance called for account: {account_id}")

        response = BalanceResponse()

        if account_id not in ACCOUNTS_DB:
            response.account_id = account_id
            response.balance = Decimal("0.00")
            response.currency = "N/A"
            response.as_of = datetime.utcnow()
            response.status_code = 404
            response.status_message = f"Account '{account_id}' not found."
            return response

        account = ACCOUNTS_DB[account_id]

        if not account["is_active"]:
            response.account_id = account_id
            response.balance = Decimal("0.00")
            response.currency = account["currency"]
            response.as_of = datetime.utcnow()
            response.status_code = 403
            response.status_message = f"Account '{account_id}' is inactive."
            return response

        response.account_id = account_id
        response.balance = account["balance"]
        response.currency = account["currency"]
        response.as_of = datetime.utcnow()
        response.status_code = 200
        response.status_message = "Balance retrieved successfully."

        logger.info(f"Balance for {account_id}: {account['balance']} {account['currency']}")
        return response

    @rpc(
        Unicode(min_occurs=1),
        Unicode(min_occurs=1),
        SpyneDecimal(min_occurs=1),
        Unicode,
        _returns=TransferResult,
        _soap_action="http://financialservices.example.com/transferFunds",
        _operation_name="transferFunds",
    )
    def transferFunds(ctx, from_account_id, to_account_id, amount, description):
        """Transfer funds between two accounts."""
        logger.info(
            f"transferFunds called: {from_account_id} -> {to_account_id}, amount: {amount}"
        )

        result = TransferResult()
        result.transaction_id = generate_transaction_id()
        result.from_account = from_account_id
        result.to_account = to_account_id
        result.amount = amount
        result.timestamp = datetime.utcnow()

        # Validate from account
        if from_account_id not in ACCOUNTS_DB:
            result.from_new_balance = Decimal("0.00")
            result.to_new_balance = Decimal("0.00")
            result.currency = "N/A"
            result.status_code = 404
            result.status_message = f"Source account '{from_account_id}' not found."
            return result

        # Validate to account
        if to_account_id not in ACCOUNTS_DB:
            result.from_new_balance = Decimal("0.00")
            result.to_new_balance = Decimal("0.00")
            result.currency = "N/A"
            result.status_code = 404
            result.status_message = f"Destination account '{to_account_id}' not found."
            return result

        from_account = ACCOUNTS_DB[from_account_id]
        to_account = ACCOUNTS_DB[to_account_id]

        # Check both accounts are active
        if not from_account["is_active"]:
            result.from_new_balance = Decimal("0.00")
            result.to_new_balance = Decimal("0.00")
            result.currency = from_account["currency"]
            result.status_code = 403
            result.status_message = f"Source account '{from_account_id}' is inactive."
            return result

        if not to_account["is_active"]:
            result.from_new_balance = Decimal("0.00")
            result.to_new_balance = Decimal("0.00")
            result.currency = to_account["currency"]
            result.status_code = 403
            result.status_message = f"Destination account '{to_account_id}' is inactive."
            return result

        # Check same currency
        if from_account["currency"] != to_account["currency"]:
            result.from_new_balance = from_account["balance"]
            result.to_new_balance = to_account["balance"]
            result.currency = from_account["currency"]
            result.status_code = 400
            result.status_message = (
                f"Currency mismatch: {from_account['currency']} vs {to_account['currency']}. "
                f"Cross-currency transfers are not supported."
            )
            return result

        # Validate amount
        if amount <= 0:
            result.from_new_balance = from_account["balance"]
            result.to_new_balance = to_account["balance"]
            result.currency = from_account["currency"]
            result.status_code = 400
            result.status_message = "Transfer amount must be positive."
            return result

        # Same account check
        if from_account_id == to_account_id:
            result.from_new_balance = from_account["balance"]
            result.to_new_balance = to_account["balance"]
            result.currency = from_account["currency"]
            result.status_code = 400
            result.status_message = "Cannot transfer to the same account."
            return result

        # Check sufficient funds
        if from_account["balance"] < amount:
            result.from_new_balance = from_account["balance"]
            result.to_new_balance = to_account["balance"]
            result.currency = from_account["currency"]
            result.status_code = 402
            result.status_message = (
                f"Insufficient funds. Available: {from_account['balance']} {from_account['currency']}, "
                f"Requested: {amount} {from_account['currency']}"
            )
            return result

        # Execute the transfer
        from_account["balance"] -= amount
        to_account["balance"] += amount

        result.currency = from_account["currency"]
        result.from_new_balance = from_account["balance"]
        result.to_new_balance = to_account["balance"]
        result.status_code = 200
        result.status_message = "Transfer completed successfully."

        # Log transaction
        transaction = {
            "transaction_id": result.transaction_id,
            "from_account": from_account_id,
            "to_account": to_account_id,
            "amount": amount,
            "currency": from_account["currency"],
            "timestamp": result.timestamp,
            "description": description or "Fund transfer",
        }
        TRANSACTIONS_LOG.append(transaction)

        logger.info(
            f"Transfer successful: {result.transaction_id}, "
            f"{amount} {from_account['currency']} from {from_account_id} to {to_account_id}"
        )
        return result

