    @rpc(
        Unicode(min_occurs=1),
        Integer,
        _returns=TransactionHistoryResponse,
        _soap_action="http://financialservices.example.com/getTransactionHistory",
        _operation_name="getTransactionHistory",
    )
    def getTransactionHistory(ctx, account_id, max_records):
        """Retrieve transaction history for a given account."""
        logger.info(f"getTransactionHistory called for account: {account_id}")

        response = TransactionHistoryResponse()
        response.account_id = account_id

        if account_id not in ACCOUNTS_DB:
            response.transactions = []
            response.total_transactions = 0
            response.status_code = 404
            response.status_message = f"Account '{account_id}' not found."
            return response

        # Filter transactions for this account
        account_transactions = [
            txn
            for txn in TRANSACTIONS_LOG
            if txn["from_account"] == account_id or txn["to_account"] == account_id
        ]

        # Sort by timestamp descending
        account_transactions.sort(key=lambda x: x["timestamp"], reverse=True)

        # Limit records
        limit = max_records if max_records and max_records > 0 else 50
        account_transactions = account_transactions[:limit]

        records = []
        for txn in account_transactions:
            record = TransactionRecord()
            record.transaction_id = txn["transaction_id"]
            record.from_account = txn["from_account"]
            record.to_account = txn["to_account"]
            record.amount = txn["amount"]
            record.currency = txn["currency"]
            record.timestamp = txn["timestamp"]
            record.description = txn["description"]
            records.append(record)

        response.transactions = records
        response.total_transactions = len(records)
        response.status_code = 200
        response.status_message = "Transaction history retrieved successfully."

        logger.info(
            f"Retrieved {len(records)} transactions for account {account_id}"
        )
