    @rpc(
        Unicode(min_occurs=1),
        Unicode(min_occurs=1),
        Unicode(min_occurs=1),
        SpyneDecimal,
        Unicode,
        Unicode,
        _returns=AccountInfo,
        _soap_action="http://financialservices.example.com/createAccount",
        _operation_name="createAccount",
    )
    def createAccount(ctx, account_id, owner_name, email, initial_balance, currency, account_type):
        """Create a new account."""
        logger.info(f"createAccount called for: {owner_name} ({account_id})")

        info = AccountInfo()

        if account_id in ACCOUNTS_DB:
            info.account_id = account_id
            info.owner_name = ""
            info.email = ""
            info.balance = Decimal("0.00")
            info.currency = "N/A"
            info.account_type = "N/A"
            info.created_at = datetime.utcnow()
            info.is_active = False
            info.status_code = 409
            info.status_message = f"Account '{account_id}' already exists."
            return info

        balance = initial_balance if initial_balance and initial_balance >= 0 else Decimal("0.00")
        curr = currency if currency else "USD"
        acc_type = account_type if account_type in ("checking", "savings") else "checking"

        new_account = {
            "account_id": account_id,
            "owner_name": owner_name,
            "email": email,
            "balance": balance,
            "currency": curr,
            "account_type": acc_type,
            "created_at": datetime.utcnow(),
            "is_active": True,
        }
        ACCOUNTS_DB[account_id] = new_account

        info.account_id = account_id
        info.owner_name = owner_name
        info.email = email
        info.balance = balance
        info.currency = curr
        info.account_type = acc_type
        info.created_at = new_account["created_at"]
        info.is_active = True
        info.status_code = 201
        info.status_message = "Account created successfully."

        logger.info(f"Account created: {account_id} for {owner_name}")
        return info


